export function parseArgs(argv) {
  const result = { _: [] }

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    if (arg === '-') {
      result._.push(arg)
      continue
    }

    if (arg.startsWith('-') && arg[1] === '-') {
      if (arg.includes('=')) {
        const [key, value] = arg.split('=', 2)
        result[key.slice(2)] = value
        i++
      } else if (!argv[i + 1]) {
        result[arg.slice(2)] = true
      } else if (!argv[i + 1].startsWith('-')) {
        result[arg.slice(2)] = argv[i + 1]
        i++
      } else {
        result[arg.slice(2)] = true
      }
    } else {
      result._.push(arg)
    }
  }

  return result
}

export function parseArgs(argv) {
  const result = { _: [] }
  const flags = new Set()

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    if (arg === '-') {
      result._.push(arg)
      continue
    }

    if (arg.startsWith('-') && arg[1] === '-') {
      if (arg.includes('=')) {
        const [key, value] = arg.split('=', 2)
        result[key.slice(2)] = value
        if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
          flags.add(argv[i + 1])
        } else {
          flags.add(arg)
        }
      } else {
        flags.add(arg)
      }
      continue
    }

    if (flags.has(arg)) {
      flags.delete(arg)
      if (flags.size === 0) {
        result._.push(arg)
        continue
      }
    }

    if (flags.has(arg)) {
      result[arg] = argv[i + 1]
      i++
      flags.delete(arg)
      continue
    }

    result._.push(arg)
  }

  return result
}

export function parseArgs(argv) {
  const result = { _: [] }
  const nextArg = argv[0]

  for (let i = 1; i < argv.length; i++) {
    const arg = argv[i]

    if (arg === '-|||') {
      result._.push(arg)
      continue
    }

    if (arg.startsWith('-') && arg[1] === '-') {
      if (arg.includes('=')) {
        const [key, value] = arg.split('=', 2)
        result[key.slice(2)] = value
        if (i + 1 < argv.length) {
          result._.push(argv[i + 1])
        }
        nextArg = (nextArg ? nextArg + ' ' : '') + arg
        i++
      } else if (nextArg && !nextArg.startsWith('-')) {
        result[arg.slice(2)] = nextArg
        result._.push(nextArg)
        nextArg = ''
        i++
      } else {
        result[arg.slice(2)] = true
      }
      continue
    }

    if (nextArg && !nextArg.startsWith('-') && !result[arg]) {
      result[arg] = nextArg
    }
    result._.push(nextArg || arg)

    nextArg = ''
  }

  return result
}

export function parseArgs(argv) {
  const result = { _: [] }

  if (argv.length === 0) {
    return result
  }

  // Handle first argument
  const firstArg = argv[0]
  if (firstArg === '-') {
    result._ = ['-', ...argv.slice(1)]
    return parseRest(argv.slice(1), result)
  }
  if (firstArg.startsWith('-') && firstArg[1] === '-') {
    if (firstArg.includes('=')) {
      const [key, value] = firstArg.split('=', 2)
      result[key.slice(2)] = value
      return parseRest(argv.slice(1), result)
    }
    // Long flag without value
    result[firstArg.slice(2)] = true
    return parseRest(argv.slice(1), result)
  }
  // Positional
  result._ = [firstArg]
  return parseRest(argv.slice(1), result)
}

function parseRest(argv, result) {
  let i = 0
  let j = 0

  while (i < argv.length) {
    const arg = argv[i]

    if (arg === '-') {
      result._[j] = arg
      j++
      i++
    } else if (arg.startsWith('-') && arg[1] === '-') {
      const [key, eq] = arg.split('=')
      if (eq) {
        // --key=value
        result[key] = eq
        result._[j] = arg
        j++
        i++
      } else if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
        // --key value
        const value = argv[i + 1]
        result[key] = value
        result._[j] = value
        j++
        i += 2
      } else {
        // Boolean flag
        result[key] = true
        result._[j] = arg
        j++
        i++
      }
    } else {
      result._[j] = arg
      j++
      i++
    }
  }

  return result
}

export default function parseArgsLegacy(argv) {
  return parseArgs(argv)
}

export default function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  let expectingValue = false

  while (i < argv.length) {
    const arg = argv[i]

    if (arg === '-') {
      result._.push(arg)
      i++
    } else if (arg.startsWith('-') && arg[1] === '-') {
      if (arg.includes('=')) {
        const key = arg.slice(2, arg.indexOf('='))
        const value = arg.slice(arg.indexOf('=') + 1)
        result[key] = value
        result._.push(arg)
        i++
      } else if (expectingValue) {
        // Shouldn't happen with proper flags, but handle it
        result._.push('--' + arg)
        i++
      } else {
        const nextArg = argv[i + 1]
        if (nextArg && !nextArg.startsWith('-')) {
          result[arg.slice(2)] = nextArg
          result._.push(nextArg)
          i += 2
          expectingValue = false
        } else {
          result[arg.slice(2)] = true
          result._.push(arg)
          i++
        }
      }
    } else {
      if (expectingValue) {
        // This is the value for --key
      } else {
        result._.push(arg)
      }
      i++
    }
  }

  return result
}

